SELECT COUNT(DISTINCT r.recipe_id) FROM recipe r LEFT JOIN food f ON r.food_id = f.food_id LEFT JOIN category c ON f.category_id = c.category_id
REPLACE(c.category_name, ' ', '') = REPLACE(#{category}, ' ', '')
AND CAST(REPLACE(r.cooking_time, '분', '') AS UNSIGNED) <= #{maxCookTime}

SELECT * FROM recipe
WHERE member_id = #{member_id}
ORDER BY recipe_id DESC
LIMIT #{size} OFFSET #{offest}

SELECT * FROM recipe
WHERE member_id = #{member_id}
ORDER BY recipe_id DESC LIMIT 5


SELECT DISTINCT r.*, f.food_name FROM recipe_view r
JOIN food f ON f.food_id = r.food_id
WHERE r.title LIKE #{pattern} OR f.food_name LIKE #{pattern}

SELECT count(*) from recipe r
join member m on r.member_id = m.member_id
join food f on r.food_id = f.food_id
join category c on f.category_id = c.category_id
where 1=1

    AND (
        r.title Like concat('%',#{keyword}, '%')
        OR m.nickname LIKE concat('%',#{keyword}, '%')
    )


AND c.category_name = #{category}



    AND r.status = #{status}



    AND r.recommend = #{recommend}

SELECT
    r.*,           
    c.category_name
FROM recipe_view r
JOIN food f ON r.food_id = f.food_id
JOIN category c ON f.category_id = c.category_id
WHERE 1=1


    AND (
        r.title LIKE CONCAT('%', #{keyword}, '%')
        OR r.nickname LIKE CONCAT('%', #{keyword}, '%')
    )



    AND c.category_name = #{category}



    AND r.status = #{status}



    AND r.recommend = #{recommend}


ORDER BY r.recipe_id DESC
LIMIT #{size} OFFSET #{offset}

